class Solution:
    def minSumSquareDiff(self, nums1: List[int], nums2: List[int], k1: int, k2: int) -> int:
        n = len(nums1)
        diff = [(a - b) ** 2 for a, b in zip(nums1, nums2)]
        diff.sort()
        k1, k2 = k1 + k2, k1 + k2
        for i in range(n - 1, -1, -1):
            if k1 >= diff[i]:
                k1 -= diff[i]
                diff[i] = 0
            elif k2 >= diff[i]:
                k2 -= diff[i]
                diff[i] = 1
            else:
                break
        return sum(d * (d + 1) // 2 for d in diff)
